# solution.py
"""Team Collaboration Manager.

An in-memory, thread-safe backend for a collaborative team workspace. It
manages users, projects, tasks, threaded messages with attachments, a
performance dashboard (completion stats and peer ratings) and a small set of
exportable reports (CSV / PDF).

The module is implemented with the Python standard library only and is
deliberately self-contained: a single shared re-entrant lock guards every
mutation so the manager is safe to drive from multiple threads, and all
accessor methods return deep copies so callers cannot mutate internal state.

Identifiers are allocated from a single global sequence, therefore an id is
unique across *every* entity type (a user, a project, a task and a message can
never collide).
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states a task can move through."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Authorization roles a user can hold."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported serialization formats for exported reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Discriminator stored on every report payload."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails a business-rule or format validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current system state."""


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary file attached to a message (only metadata is retained)."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A member of the workspace."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A scheduled body of work owned by a single user."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""


@dataclass
class Task:
    """A unit of work inside a project, optionally assigned to a user."""

    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    """A threaded message attached to either a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating (1-5) given by one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# Sentinel used to distinguish "argument omitted" from "argument set to None".
_UNSET = object()


# ---------------------------------------------------------------------------
# Stores
# ---------------------------------------------------------------------------
# Each store is a thin data container that shares the manager's single lock.
# Keeping the data partitioned by type mirrors a repository-per-aggregate
# design while the shared lock keeps every cross-store operation atomic.
class _BaseStore:
    """Common base giving every store a reference to the shared lock."""

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._items: Dict[int, User] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._items: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._items: Dict[int, Task] = {}
        # Secondary index: assignee_id -> set of task ids.
        self._by_assignee: Dict[int, set] = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._items: Dict[int, Message] = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        # ratee_id -> list of Rating
        self._ratings: Dict[int, List[Rating]] = {}


class _ReportStore(_BaseStore):
    """Stateless store; exists so report logic shares the common lock."""


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Facade exposing every workspace operation.

    Parameters
    ----------
    now:
        A zero-argument callable returning the "current" :class:`datetime`.
        Injecting a clock keeps the manager deterministic under test. When
        omitted, :func:`datetime.now` is used.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_seq = 0

        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- internal helpers --------------------------------------------------
    def _next_id(self) -> int:
        """Return the next globally-unique id. Caller must hold the lock."""
        self._id_seq += 1
        return self._id_seq

    def _require_user(self, user_id: int) -> User:
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    @staticmethod
    def _clean_username(username) -> str:
        if not isinstance(username, str):
            raise ValidationError("username must be a string")
        cleaned = username.strip()
        if not cleaned:
            raise ValidationError("username cannot be empty")
        return cleaned

    @staticmethod
    def _clean_email(email) -> str:
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("invalid email address")
        return cleaned

    def _ensure_unique_user(self, username: str, email: str, exclude_id) -> None:
        lname = username.lower()
        lmail = email.lower()
        for uid, user in self.users._items.items():
            if uid == exclude_id:
                continue
            if user.username.lower() == lname:
                raise DuplicateError("username already in use")
            if user.email.lower() == lmail:
                raise DuplicateError("email already in use")

    def _tasks_for_assignee(self, user_id: int) -> List[Task]:
        ids = self.tasks._by_assignee.get(user_id, set())
        return [self.tasks._items[tid] for tid in ids if tid in self.tasks._items]

    def _index_assignee(self, task_id: int, assignee_id: int) -> None:
        self.tasks._by_assignee.setdefault(assignee_id, set()).add(task_id)

    def _deindex_assignee(self, task_id: int, assignee_id: int) -> None:
        bucket = self.tasks._by_assignee.get(assignee_id)
        if bucket is not None:
            bucket.discard(task_id)
            if not bucket:
                self.tasks._by_assignee.pop(assignee_id, None)

    def _set_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        if task.assignee_id == assignee_id:
            return
        if task.assignee_id is not None:
            self._deindex_assignee(task.id, task.assignee_id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self._index_assignee(task.id, assignee_id)

    def _delete_task_internal(self, task_id: int) -> None:
        task = self.tasks._items.get(task_id)
        if task is None:
            return
        if task.assignee_id is not None:
            self._deindex_assignee(task_id, task.assignee_id)
        for mid in [
            mid for mid, m in self.messages._items.items() if m.task_id == task_id
        ]:
            del self.messages._items[mid]
        del self.tasks._items[task_id]

    @staticmethod
    def _completion_seconds(task: Task) -> Optional[float]:
        if (
            task.status == TaskStatus.COMPLETED
            and task.started_at is not None
            and task.completed_at is not None
        ):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    # -- user management ---------------------------------------------------
    def register_user(self, username, email, role: UserRole = UserRole.MEMBER) -> User:
        with self._lock:
            name = self._clean_username(username)
            mail = self._clean_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            self._ensure_unique_user(name, mail, exclude_id=None)
            uid = self._next_id()
            user = User(
                id=uid,
                username=name,
                email=mail,
                role=role,
                created_at=self._now(),
            )
            self.users._items[uid] = user
            return copy.deepcopy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return copy.deepcopy(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            ordered = sorted(self.users._items.values(), key=lambda u: u.id)
            return [copy.deepcopy(u) for u in ordered]

    def update_user(
        self, user_id: int, username=_UNSET, email=_UNSET, role=_UNSET
    ) -> User:
        with self._lock:
            user = self._require_user(user_id)
            new_name = user.username
            new_mail = user.email
            new_role = user.role
            if username is not _UNSET:
                new_name = self._clean_username(username)
            if email is not _UNSET:
                new_mail = self._clean_email(email)
            if role is not _UNSET:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role
            if username is not _UNSET or email is not _UNSET:
                self._ensure_unique_user(new_name, new_mail, exclude_id=user_id)
            user.username = new_name
            user.email = new_mail
            user.role = new_role
            return copy.deepcopy(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            self._require_user(user_id)
            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")
            for task in self.tasks._items.values():
                if (
                    task.assignee_id == user_id
                    and task.status != TaskStatus.COMPLETED
                ):
                    raise ConflictError("user has open assigned tasks")
            del self.users._items[user_id]
            self.tasks._by_assignee.pop(user_id, None)

    # -- project management ------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description: str = ""
    ) -> Project:
        with self._lock:
            self._require_user(owner_id)
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name cannot be empty")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            pid = self._next_id()
            project = Project(
                id=pid,
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
            )
            self.projects._items[pid] = project
            return copy.deepcopy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return copy.deepcopy(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            ordered = sorted(self.projects._items.values(), key=lambda p: p.id)
            return [copy.deepcopy(p) for p in ordered]

    def update_project(
        self,
        project_id: int,
        name=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
        description=_UNSET,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)
            new_name = project.name
            new_start = project.start_date
            new_end = project.end_date
            new_desc = project.description
            if name is not _UNSET:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name cannot be empty")
                new_name = name.strip()
            if start_date is not _UNSET:
                new_start = start_date
            if end_date is not _UNSET:
                new_end = end_date
            if description is not _UNSET:
                new_desc = description or ""
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")
            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            project.description = new_desc
            return copy.deepcopy(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)
            task_ids = [
                tid
                for tid, t in self.tasks._items.items()
                if t.project_id == project_id
            ]
            for tid in task_ids:
                self._delete_task_internal(tid)
            msg_ids = [
                mid
                for mid, m in self.messages._items.items()
                if m.project_id == project_id
            ]
            for mid in msg_ids:
                del self.messages._items[mid]
            del self.projects._items[project_id]

    # -- task management ---------------------------------------------------
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title cannot be empty")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            tid = self._next_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks._items[tid] = task
            if assignee_id is not None:
                self._index_assignee(tid, assignee_id)
            return copy.deepcopy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return copy.deepcopy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            tasks = [
                t for t in self.tasks._items.values() if t.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            self._require_user(assignee_id)
            tasks = self._tasks_for_assignee(assignee_id)
            tasks.sort(key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return copy.deepcopy(task)

    def set_deadline(self, task_id: int, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id: int, status) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return copy.deepcopy(task)

    # -- messaging ---------------------------------------------------------
    def _build_attachments(
        self, attachments: Optional[List[Tuple[str, bytes]]], uploader_id: int
    ) -> List[Attachment]:
        built: List[Attachment] = []
        if attachments:
            now = self._now()
            for entry in attachments:
                filename, data = entry
                if not isinstance(filename, str) or not filename:
                    raise ValidationError("attachment filename cannot be empty")
                size = len(data) if data is not None else 0
                built.append(
                    Attachment(
                        filename=filename,
                        size=size,
                        uploaded_by=uploader_id,
                        uploaded_at=now,
                    )
                )
        return built

    def post_message(
        self,
        author_id: int,
        body: str,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None and parent_id not in self.messages._items:
                raise NotFoundError("parent message {0} not found".format(parent_id))
            built = self._build_attachments(attachments, author_id)
            text = body if isinstance(body, str) else ""
            if not text.strip() and not built:
                raise ValidationError(
                    "message body cannot be empty without attachments"
                )
            mid = self._next_id()
            message = Message(
                id=mid,
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=self._now(),
                edited_at=None,
            )
            self.messages._items[mid] = message
            return copy.deepcopy(message)

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            text = new_body if isinstance(new_body, str) else ""
            if not text.strip() and not message.attachments:
                raise ValidationError(
                    "message body cannot be empty without attachments"
                )
            message.body = text
            message.edited_at = self._now()
            return copy.deepcopy(message)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may add attachments"
                )
            if not isinstance(filename, str) or not filename:
                raise ValidationError("attachment filename cannot be empty")
            size = len(data) if data is not None else 0
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=uploader_id,
                    uploaded_at=self._now(),
                )
            )
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            messages = [
                m
                for m in self.messages._items.values()
                if m.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return [copy.deepcopy(m) for m in messages]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            messages = [
                m for m in self.messages._items.values() if m.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return [copy.deepcopy(m) for m in messages]

    def delete_message(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            del self.messages._items[message_id]

    # -- performance dashboard --------------------------------------------
    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = [
                d
                for d in (
                    self._completion_seconds(t)
                    for t in self._tasks_for_assignee(user_id)
                )
                if d is not None
            ]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self, rater_id: int, ratee_id: int, score: int, feedback: str = "", task_id=None
    ) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)
            rid = self._next_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._ratings.setdefault(ratee_id, []).append(rating)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance._ratings.get(user_id, [])
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            durations = [
                d
                for d in (self._completion_seconds(t) for t in tasks)
                if d is not None
            ]
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self.performance._ratings.get(user_id, [])
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

