    def export_report(self, report, report_format) -> object:
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if report_format == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    # -- export helpers ----------------------------------------------------
    def _export_csv(self, report: Dict[str, object]) -> str:
        report_type = report.get("report_type")
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([row.get(col) for col in header])
        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id")])
            writer.writerow(["project_name", report.get("project_name")])
            writer.writerow(["total_tasks", report.get("total_tasks")])
            for status, count in (report.get("status_counts", {}) or {}).items():
                writer.writerow(["status:{0}".format(status), count])
            writer.writerow(["completion_rate", report.get("completion_rate")])
            writer.writerow(["overdue_tasks", report.get("overdue_tasks")])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "task_id",
                "title",
                "status",
                "project_id",
                "started_at",
                "completed_at",
            ]
            writer.writerow(header)
            for task in report.get("tasks", []):
                writer.writerow([task.get(col) for col in header])
        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([key, value])
        return buffer.getvalue()

    def _export_pdf(self, report: Dict[str, object]) -> bytes:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, sub_value))
            elif isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
                for item in value:
                    lines.append("  - {0}".format(item))
            else:
                lines.append("{0}: {1}".format(key, value))
        return self._make_pdf(lines)

    @staticmethod
    def _make_pdf(lines: List[str]) -> bytes:
        def escape(text: str) -> str:
            return (
                str(text)
                .replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )

        content_parts = ["BT", "/F1 12 Tf", "14 TL", "50 750 Td"]
        for index, line in enumerate(lines or [""]):
            if index > 0:
                content_parts.append("T*")
            content_parts.append("({0}) Tj".format(escape(line)))
        content_parts.append("ET")
        stream = "\n".join(content_parts)

        objects = [
            "<< /Type /Catalog /Pages 2 0 R >>",
            "<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                "/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
            ),
            "<< /Length {0} >>\nstream\n{1}\nendstream".format(
                len(stream.encode("latin-1")), stream
            ),
            "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = "%PDF-1.4\n"
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf.encode("latin-1")))
            pdf += "{0} 0 obj\n{1}\nendobj\n".format(number, body)
        xref_position = len(pdf.encode("latin-1"))
        size = len(objects) + 1
        pdf += "xref\n0 {0}\n".format(size)
        pdf += "0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset)
        pdf += (
            "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n".format(
                size, xref_position
            )
        )
        return pdf.encode("latin-1")
